graphql.query:
query TicketByOrder($order_code: String!) {
  ticketByOrder(order_code: $order_code) {
    id
    order_code
    ticket_code
    concert_id
    user_id
    status
    issued_at
    created_at
  }
}

query TicketByCode($ticket_code: String!) {
  ticket(ticket_code: $ticket_code) {
    id
    order_code
    ticket_code
    concert_id
    user_id
    status
    issued_at
    created_at
  }
}

query MyTickets($user_id: String!) {
  myTickets(user_id: $user_id) {
    id
    order_code
    ticket_code
    concert_id
    status
    issued_at
  }
}

body.raw:
{
